package Process;

import org.apache.commons.lang3.tuple.Pair;

import java.util.*;

public class Uber {
    public static void main(String[] args) {
        Sol sol = new Sol();
        String[] transactions = new String[]{
                "A->B:100",
                "B->C:50",
                "C->A:50",
                "B->A:25",
                "A->C:150",
                "D->C:999"
        };

        sol.addTranasaction(transactions);

        System.out.println(sol.getTransactions("A"));
        System.out.println(sol.getTransactions("B", "A"));;
        System.out.println(sol.getAllTranscations());
    }
}

class Sol {
    Map<String, Map<String, Integer>> balanceMap;

    public Sol(){
        balanceMap = new HashMap<>();
    }

    void addTransaction(String statement){
        String[] splittedStatement = statement.split(":");
        int val = Integer.parseInt(splittedStatement[1]);
        String[] fromTo = splittedStatement[0].split("->");
        String from = fromTo[0];
        String to = fromTo[1];

        addValue(from, to, val);

    }


    private void addValue(String from, String to, int val){
        Map<String, Integer> fromBalanceMap = balanceMap.getOrDefault(from, new HashMap<>());
        balanceMap.put(from,fromBalanceMap);
        Map<String, Integer> toBalanceMap = balanceMap.getOrDefault(to, new HashMap<>());
        balanceMap.put(to, toBalanceMap);

        int fromToBalance = fromBalanceMap.getOrDefault(to, 0);
        fromToBalance  += val;
        fromBalanceMap.put(to, fromToBalance);

        int toFromBalance = toBalanceMap.getOrDefault(from, 0);
        toFromBalance -= val;
        toBalanceMap.put(from, toFromBalance);
    }

    void addTranasaction(String[] statments) {
        for(String statement : statments){
            addTransaction(statement);
        }

    }

    List<String> getTransactions(String bank){
        Map<String, Integer> balanceMap = this.balanceMap.getOrDefault(bank, new HashMap<>());
        List<String> res = new ArrayList<>();
        for(Map.Entry entry:  balanceMap.entrySet()){
            String currBalance=  bank + "->"+  entry.getKey() + " : " + entry.getValue();
            res.add(currBalance);
        }

        return res;
    }

    List<String> getAllTranscations(){
        //using visitedNode to avoid duplicate entries like A->B:100 and B->A:-100
        Set<String> visitedNodes = new HashSet<>();
        List<String> res = new ArrayList<>();

        for(Map.Entry<String, Map<String,Integer>> entry: balanceMap.entrySet()){
           String key = entry.getKey();
           Map<String, Integer> currBalance = entry.getValue();
           visitedNodes.add(key);
           for(Map.Entry<String,Integer> balance : currBalance.entrySet()){
               String nextKey = balance.getKey();
               int val = balance.getValue();
               if(visitedNodes.contains(nextKey)){
                   continue;
               }
                res.add(key + "->" + nextKey + " : " + val);
           }
        }

        return res;
    }


    String getTransactions(String fromBank, String toBank){
        Map<String, Integer> balanceMap = this.balanceMap.getOrDefault(fromBank, new HashMap<>());
        int val  = balanceMap.getOrDefault(toBank, 0);
        return fromBank + "->" + toBank + " : " + val;
    }


}

